    printf("a = %d, b = %d, c = %d\n", a, b, c);
    printf("d = %f, e = %f, f = %f\n", d, e, f);
    return(0);
}
a = -2100233488, b = 31449, c = -1547096624
d = 0.000000, e = -0.000000, f = 0.000000

